import { Hono } from 'hono';
import bcrypt from 'bcrypt';

const app = new Hono();

app.post('/login', async (c) => {
  const { email, password } = await c.req.json<{ email: string; password: string }>();

  // Simulate user lookup
  const users = [
    { id: 1, email: 'user@example.com', hashedPassword: '$2b$10$dGhlIHNhbXBsZSBub25jZQ==' }, // bcrypt hash of "password"
  ];

  const user = users.find(u => u.email === email);

  if (!user) {
    return c.json({ error: 'User not found' }, 404);
  }

  // Compare passwords
  const isPasswordValid = await bcrypt.compare(password, user.hashedPassword);

  if (!isPasswordValid) {
    return c.json({ error: 'Invalid password' }, 401);
  }

  // Generate a session token (simulated)
  const sessionToken = 'generated-session-token';

  // Set the session cookie
  c.cookie('session', sessionToken, { maxAge: 3600 * 24 * 7 }); // 7 days

  return c.json({ message: 'Login successful' });
});

export default app;

import { defineConfig } from 'hono/config';

export default defineConfig({
  port: 3000,
});

